```class Solution {
public:
    int kIncreasing(vector<int>& arr, int k) {
        int n = arr.size(), res = 0;
        for (int i = k; i < n; ++i) {
            if (arr[i - k] > arr[i]) {
                res += arr[i - k] - arr[i];
                arr[i] = arr[i - k];
            }
        }
        return res;
    }
};
